"""HLD Key Technologies: PostgreSQL, Flink, ZooKeeper — 20 deep MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def postgresql_lesson() -> Lesson:
    return Lesson(id="hld-postgresql", number=122, title="PostgreSQL",
        focus=("MVCC","WAL","VACUUM","indexes","replication","partitioning","JSONB"),
        overview="PostgreSQL is the most versatile RDBMS. Know MVCC, WAL, replication, and when to use it vs alternatives.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("pg-1","What is PostgreSQL's MVCC?","hard",("postgresql",),("Multi-Version Concurrency Control: each transaction sees a snapshot; readers don't block writers","A communication pattern where services exchange messages through a centralized broker","A resilience pattern that isolates failures in one subsystem from propagating to others","A load shedding strategy that drops low-priority requests when resource utilization is high"),0,"MVCC: each row has xmin/xmax marking which transactions can see it. No read locks needed."),
        quiz("pg-2","What is the WAL in PostgreSQL?","hard",("postgresql",),("Write-Ahead Log: all changes recorded before applying, ensuring crash recovery and enabling replication","A technique where the server pre-fetches resources based on predicted client needs","An index maintenance operation that rebuilds fragmented pages for better scan performance","A testing approach that injects controlled failures to verify system recovery behavior"),0,"WAL: sequential writes for durability. Streaming replication sends WAL to followers."),
        quiz("pg-3","What is VACUUM and why is it necessary?","hard",("postgresql",),("Reclaims storage from dead tuples (old row versions) left by MVCC after updates/deletes","A state synchronization approach that reconciles differences using Merkle tree comparison","A consensus protocol that uses a rotating leader to distribute write coordination load","A flow control mechanism that prevents the sender from overwhelming the receiver"),0,"Without VACUUM, tables bloat with dead tuples. autovacuum handles this automatically in most cases."),
        quiz("pg-4","What is the difference between HOT update and regular update?","hard",("postgresql",),("Heap-Only Tuple: if no indexed columns change, the new version stays on the same page — no index update needed","A coordination service that uses ephemeral nodes for automatic failure detection","A persistence mechanism that snapshots the cache state to disk for crash recovery","A consistency model where reads from any replica are guaranteed to be monotonically fresh"),0,"HOT updates avoid index maintenance, significantly improving update performance when only non-indexed columns change."),
        quiz("pg-5","What is PostgreSQL's streaming replication?","hard",("postgresql",),("Continuous WAL shipping from primary to standby in real-time; standby can serve read queries","A data pipeline stage that transforms and enriches events before writing to storage","A mechanism that compresses HTTP headers to reduce bandwidth on repeated requests","A deployment strategy that gradually shifts traffic from the old version to the new one"),0,"Streaming replication: sub-second lag. Synchronous mode waits for standby confirmation (slower but consistent)."),
        quiz("pg-6","What is logical replication in PostgreSQL?","hard",("postgresql",),("Replicates at the logical (row/table) level instead of physical WAL; supports selective table replication","A warming strategy that pre-loads data based on access frequency from the previous day","A backup mechanism that captures incremental changes since the last full snapshot","A transport layer optimization that reduces round-trip overhead using multiplexing"),0,"Logical replication: replicate specific tables, cross-version, or to different schemas. Uses publication/subscription."),
        quiz("pg-7","What are PostgreSQL's isolation levels?","hard",("postgresql",),("Read Uncommitted, Read Committed (default), Repeatable Read, and Serializable","A replication technique that synchronously mirrors writes to a standby for zero data loss","A congestion avoidance algorithm that dynamically adjusts the transmission window","A sharding approach that distributes cached entries across nodes by consistent hashing"),0,"Read Committed: sees only committed data at statement start. Serializable: full ACID, detects anomalies."),
        quiz("pg-8","What is a PostgreSQL GiST index?","hard",("postgresql",),("Generalized Search Tree: supports geometric/spatial data, full-text search, and range types","A DNS-based technique that distributes queries across multiple authoritative servers","A security protocol that authenticates both client and server during the handshake","A routing strategy that directs traffic based on geographic proximity of the client"),0,"GiST: used for PostGIS geometry queries, range containment, and nearest-neighbor search."),
        quiz("pg-9","What is PostgreSQL partitioning?","medium",("postgresql",),("Splitting a large table into smaller physical pieces (range, list, or hash) within the same database","A transaction isolation level that prevents phantom reads using predicate locking","A data structure that stores cache metadata compactly using probabilistic counting","A membership protocol where nodes periodically exchange state with random cluster peers"),0,"Partitioning improves query performance and maintenance for large tables. Partition pruning skips irrelevant partitions."),
        quiz("pg-10","What is the JSONB type in PostgreSQL?","medium",("postgresql",),("Binary JSON with indexing support (GIN) — queryable, indexable document storage within PostgreSQL","A pattern where incoming requests are buffered and processed in priority-ordered batches","A monitoring approach that aggregates metrics from multiple sources into unified dashboards","A scheduling algorithm that assigns tasks to workers based on estimated completion time"),0,"JSONB: store semi-structured data. Create GIN indexes for fast @>, ?, and jsonpath queries."),
        quiz("pg-11","What is connection pooling and why is it critical for PostgreSQL?","hard",("postgresql",),("PostgreSQL forks a new process per connection (~10MB each); pooling (PgBouncer) reuses connections","A failure detection mechanism using heartbeat intervals and configurable timeout thresholds","A protocol that batches multiple requests into a single TCP segment for efficiency","A prefetching algorithm that predicts future access patterns from recent query history"),0,"Without pooling, 1000 connections = 10GB RAM just for processes. PgBouncer: transaction-level pooling."),
        quiz("pg-12","What is a CTE (Common Table Expression) in PostgreSQL?","medium",("postgresql",),("A named temporary result set (WITH clause) that makes complex queries readable and can be recursive","A partitioning strategy that splits data based on a hash of the composite primary key","A replication technique that mirrors hot cache entries across multiple nodes for availability","A replication strategy where writes go to any node and conflicts are resolved on read"),0,"WITH RECURSIVE: powerful for tree/graph traversal (org charts, category hierarchies)."),
        quiz("pg-13","What is pg_stat_statements?","hard",("postgresql",),("An extension tracking query statistics (execution count, total time, mean time) for performance analysis","A partitioning algorithm that assigns data based on a hash of the geographic region","A clock synchronization technique that uses NTP with bounded drift for ordering events","A schema design pattern that embeds frequently accessed data to avoid join overhead"),0,"pg_stat_statements: find your slowest queries, most frequent queries, and optimization opportunities."),
        quiz("pg-14","What is the TOAST mechanism?","hard",("postgresql",),("The Oversized-Attribute Storage Technique: automatically compresses and stores large values out-of-line","A cache coherence protocol that broadcasts invalidation messages to all cache tiers","A monitoring tool that tracks query execution plan and identifies slow running queries","A query optimization strategy that rewrites subqueries into more efficient join patterns"),0,"TOAST: values >2KB are compressed and stored in a separate TOAST table. Transparent to the application."),
        quiz("pg-15","What is a tablespace in PostgreSQL?","medium",("postgresql",),("A location on disk where database objects are stored — allows placing tables on different disks/SSDs","A connection management approach that limits concurrent sessions to prevent overload","A monitoring tool that tracks hit rates, eviction counts, and memory usage per cache pool","A connection management approach that pins clients to specific backend instances"),0,"Put hot tables on SSD tablespace, cold data on HDD. Different performance tiers within one database."),
        quiz("pg-16","What is PostgreSQL's query planner?","hard",("postgresql",),("The optimizer that decides how to execute a query: which indexes to use, join strategy, scan type","A technique that partitions workload across worker pools based on resource requirements","A process that periodically reconciles state between systems to detect and fix drift","An eviction algorithm that considers both recency and frequency when selecting victims"),0,"EXPLAIN ANALYZE: see the actual execution plan. The planner uses statistics (pg_stats) to estimate costs."),
        quiz("pg-17","What are advisory locks in PostgreSQL?","hard",("postgresql",),("Application-level cooperative locks that don't lock any actual rows — used for distributed coordination","A storage engine optimization that pre-sorts data on disk for sequential access patterns","A serialization format that reduces cache entry size through schema-aware compression","Standard database transaction row locks configured with optimistic locking"),0,"Advisory locks: pg_advisory_lock(key). Used for job deduplication, rate limiting, and distributed locking."),
        quiz("pg-18","What is the difference between SERIAL and IDENTITY columns?","medium",("postgresql",),("SERIAL creates a sequence implicitly; IDENTITY (SQL standard) is more explicit and prevents accidental overrides","They are identical in implementation; the choice is purely cosmetic","IDENTITY is a legacy, non-recommended data type slated for removal","SERIAL is the modern SQL standard that replaces older IDENTITY definitions"),0,"GENERATED ALWAYS AS IDENTITY: SQL-standard way. Prevents manual ID insertion (GENERATED BY DEFAULT allows it)."),
        quiz("pg-19","What is PostgreSQL's handling of full-text search?","hard",("postgresql",),("Built-in tsvector/tsquery with GIN indexes — tokenization, stemming, ranking without needing Elasticsearch","PostgreSQL does not support full-text search without third-party plugins","It supports only basic pattern matching using standard LIKE or regex filters","It requires an external search server like Elasticsearch to parse documents"),0,"pg full-text search: to_tsvector('english', text) @@ to_tsquery('search & term'). Good enough for many apps."),
        quiz("pg-20","When should you NOT use PostgreSQL?","hard",("postgresql",),("When you need massive write throughput (>100K writes/sec), horizontal scaling, or schemaless flexibility at scale","When your application schema requires more than 50 table entities","When the data is highly relational and requires multiple table joins","You should always choose PostgreSQL regardless of scale or throughput"),0,"PostgreSQL scales vertically well but horizontal scaling is limited. Consider Cassandra/DynamoDB for massive writes."),
    ))

def flink_lesson() -> Lesson:
    return Lesson(id="hld-flink", number=123, title="Flink",
        focus=("stream processing","event time","watermarks","state","checkpointing","exactly-once"),
        overview="Flink is the go-to for real-time stream processing. Know event time, watermarks, and exactly-once semantics.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("flink-1","What is Apache Flink?","medium",("flink",),("A distributed stream processing framework with event-time semantics, stateful computation, and exactly-once guarantees","A batch-only analytics engine similar to Apache Hadoop MapReduce","A message broker used to ingest and queue telemetry records","A NoSQL key-value database optimized for real-time reads"),0,"Flink processes unbounded streams in real-time. Also handles batch as a special case of streaming."),
        quiz("flink-2","What is event time vs processing time?","hard",("flink",),("Event time: when the event actually occurred. Processing time: when the system processes it. Event time handles late arrivals","They are identical concepts, differing only in naming standards","Event time is the database server clock value recorded at index commit","Processing time is the most accurate clock metric for sorting events"),0,"Event time ensures correct results even when events arrive out of order or late."),
        quiz("flink-3","What are watermarks in Flink?","hard",("flink",),("Markers declaring that no events with timestamps earlier than the watermark will arrive — triggers window computation","A state snapshot indicator used to resume jobs after failure","A network connection keep-alive signal sent between worker nodes","A timestamp field extracted from the event's payload metadata"),0,"Watermarks: 'all events before time T have arrived.' Windows fire when watermark passes window end time."),
        quiz("flink-4","What is windowing in Flink?","hard",("flink",),("Grouping events into finite sets for aggregation: tumbling (fixed, non-overlapping), sliding, session, global","A memory caching layout used to store intermediate aggregate states","A key-value partitioning scheme that routes records to specific shards","A pagination API used to display query results in user interfaces"),0,"Tumbling: 5-min non-overlapping. Sliding: 5-min window every 1 min. Session: gap-based grouping."),
        quiz("flink-5","What is Flink's checkpointing mechanism?","hard",("flink",),("Periodic consistent snapshots of operator state to durable storage, enabling exactly-once recovery","A transaction log file where operator exceptions are saved","A monitoring dashboard utility that checks cluster node health","A manual backup command triggered by system operators during deployment"),0,"Checkpointing: barrier flows through the graph. Each operator saves state when barrier arrives. Asynchronous."),
        quiz("flink-6","How does Flink achieve exactly-once semantics?","hard",("flink",),("Checkpointing + barrier alignment + idempotent sinks or two-phase commit sinks","By executing all computations inside a single-threaded server process","By restricting streams to at-least-once delivery without alignment","Exactly-once is mathematically impossible to achieve in distributed systems"),0,"Exactly-once within Flink. End-to-end exactly-once requires transactional sinks (Kafka transactions, 2PC)."),
        quiz("flink-7","What is Flink's state backend?","hard",("flink",),("Storage for operator state: MemoryStateBackend (dev), FsStateBackend (moderate), RocksDBStateBackend (production)","A relational database configured to store intermediate query tables","A message queue used to buffer events between stream operators","A centralized configuration file containing worker cluster details"),0,"RocksDB: state larger than memory, spills to disk. Incremental checkpoints for large state."),
        quiz("flink-8","What is a keyed stream in Flink?","medium",("flink",),("A stream partitioned by key — all events with the same key go to the same operator instance for stateful processing","A query filter stream that discards messages missing a key field","An encrypted stream that requires cryptographic keys to read","A sorted stream that orders events sequentially by arrival time"),0,"keyBy(key) partitions the stream. Stateful operations (aggregations, joins) work per key."),
        quiz("flink-9","What is the difference between Flink and Spark Streaming?","hard",("flink",),("Flink: true stream processing (event-by-event). Spark: micro-batch (processes small batches). Flink has lower latency","Spark Streaming is a true stream processing engine with lower latency than Flink","Flink is a batch-only framework that does not support streaming updates","They are identical frameworks managed by the same open-source project"),0,"Flink: millisecond latency. Spark Structured Streaming: ~100ms+ latency due to micro-batching."),
        quiz("flink-10","What is Flink's TaskManager and JobManager?","medium",("flink",),("JobManager: coordinates jobs, scheduling, checkpointing. TaskManager: executes operators, manages state","JobManager executes individual tasks while TaskManager manages configuration files","TaskManager coordinates all cluster resources while JobManager runs on master","They are synonyms for the same cluster manager process"),0,"JobManager: brain (1 or HA pair). TaskManagers: muscle (many, run parallel tasks)."),
        quiz("flink-11","What is a Flink savepoint vs checkpoint?","hard",("flink",),("Checkpoints are automatic and periodic; savepoints are manually triggered for upgrades, migrations, and debugging","Checkpoints are manual backups; savepoints are scheduled automatically","Savepoints are transient memory buffers; checkpoints are written to disk","They are identical features, named differently for compatibility reasons"),0,"Savepoints: portable snapshots. Use for Flink version upgrades, code changes, and cluster migrations."),
        quiz("flink-12","How does Flink handle late events?","hard",("flink",),("Allowed lateness parameter: late events within the allowed window update results; beyond that, sent to side output","By dropping all late events automatically to preserve memory","By processing late events immediately and overwriting previous outputs","By pausing the entire stream pipeline until the late events arrive"),0,"allowedLateness(Duration) + sideOutputLateData: handle stragglers gracefully."),
        quiz("flink-13","What is Flink's DataStream API vs Table API?","medium",("flink",),("DataStream: low-level Java/Python API for custom processing. Table API/SQL: high-level declarative queries","Table API is the low-level Java framework; DataStream is the high-level SQL","DataStream is a SQL-only interface; Table API is a procedural compiler","They are identical APIs, differing only in language binding compatibility"),0,"Table API: SQL-like. DataStream: full control. Both can be mixed in the same application."),
        quiz("flink-14","What is a broadcast state in Flink?","hard",("flink",),("State that is sent to all parallel instances of an operator — used for configuration updates, rule changes","A logging level that broadcasts error messages to all monitors","A distributed cache memory block shared across client applications","A partition routing rule that distributes events round-robin"),0,"Broadcast state: small reference data (rules, config) distributed to all operator instances."),
        quiz("flink-15","What is the operator chain optimization?","hard",("flink",),("Flink chains compatible operators into a single task to avoid serialization/network overhead between them","A database query optimizer that compiles SQL into execution plans","A configuration setting that limits concurrent worker thread counts","A deployment strategy that distributes tasks across nodes evenly"),0,"Chaining: map → filter → flatMap run in the same thread, avoiding serialization between each step."),
        quiz("flink-16","What is Flink CDC?","hard",("flink",),("Change Data Capture connectors that ingest database changes (MySQL, PostgreSQL) as a Flink stream","A backup tool that runs periodic snapshots of relational databases","A Kafka Connect schema validator used to check message formats","A cluster monitoring utility that tracks Flink task latency"),0,"Flink CDC: read database binlog/WAL as a stream. Build real-time materialized views from DB changes."),
        quiz("flink-17","What is the parallelism in Flink?","medium",("flink",),("The number of parallel instances of each operator — determines throughput and resource usage","A single-threaded mode that processes events in sequence","The count of standby replicas configured for job recovery","A deployment parameter that specifies the count of TaskManagers"),0,"Set parallelism per operator, per job, or globally. More parallelism = more throughput but more resources."),
        quiz("flink-18","What is a process function in Flink?","hard",("flink",),("The most flexible API: access to event, state, timers, and side outputs for complex event processing","A configuration block that sets up stream connection adapters","A utility class containing math and string helper functions","A monitoring hook that alerts operators when CPU levels spike"),0,"ProcessFunction: register timers, manage state, emit to side outputs. Full control over event processing."),
        quiz("flink-19","What is Flink's exactly-once sink with Kafka?","hard",("flink",),("Two-phase commit: Flink pre-commits to Kafka during checkpoint, commits on checkpoint completion","At-most-once delivery where failed messages are dropped immediately","At-least-once delivery that requires the client to deduplicate messages","Exactly-once sinks are not possible under any database configurations"),0,"TwoPhaseCommitSinkFunction: pre-commit on checkpoint barrier, commit on checkpoint success, abort on failure."),
        quiz("flink-20","When should you use Flink vs Kafka Streams?","hard",("flink",),("Flink: separate cluster, complex event processing, exactly-once, large state. Kafka Streams: library, embedded in app, simpler","They are identical frameworks, differing only in licensing costs","You should always use Flink since it has lower resource consumption","You should always choose Kafka Streams as it supports non-Kafka sources"),0,"Kafka Streams: simple, no separate cluster, embedded. Flink: more powerful, separate cluster, advanced features."),
    ))

def zookeeper_lesson() -> Lesson:
    return Lesson(id="hld-zookeeper", number=124, title="ZooKeeper",
        focus=("znodes","watches","leader election","distributed locks","ZAB protocol","ephemeral nodes"),
        overview="ZooKeeper is the coordination service for distributed systems. Know its primitives and consensus protocol.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("zk-1","What is ZooKeeper used for?","medium",("zookeeper",),("Distributed coordination: leader election, configuration management, service discovery, distributed locking","Full-text search indexing and query relevance optimization","High-throughput message queuing and event buffering","Storing large user files and binary database backups"),0,"ZooKeeper provides primitives for coordination. Used by Kafka, HBase, and Hadoop."),
        quiz("zk-2","What is a znode?","hard",("zookeeper",),("A data node in ZooKeeper's hierarchical namespace (like a filesystem) storing up to 1MB of data","A physical server machine in the ZooKeeper cluster pool","A record in a relational database table managed by ZooKeeper","A network router that connects client nodes to coordinators"),0,"Znodes: /app/config, /app/leader. Each can hold data and have children. Like a small filesystem."),
        quiz("zk-3","What is an ephemeral znode?","hard",("zookeeper",),("A znode that exists only while the session that created it is alive — auto-deleted on disconnect","A permanent configuration node that must be deleted manually","A temporary memory cache block used for query speedups","A replication backup node that mirrors primary data folders"),0,"Ephemeral znodes: auto-cleanup when client disconnects. Foundation for leader election and service discovery."),
        quiz("zk-4","What is a sequential znode?","hard",("zookeeper",),("A znode with an auto-incrementing suffix — used for queue ordering and fair leader election","A sorted database index that organizes records by creation time","An ordered list data type supported in the memory registry","A numbered backup file containing historical server logs"),0,"Create /lock/lock- with SEQUENTIAL flag → ZK appends /lock/lock-0000000001. Lowest number wins the lock."),
        quiz("zk-5","How does leader election work in ZooKeeper?","hard",("zookeeper",),("Each candidate creates an ephemeral sequential node; the node with the lowest sequence number becomes leader","Selecting a candidate node randomly using a cluster seed value","Running a voting protocol where all clients choose a coordinator","Requiring system operators to assign the leader node manually"),0,"Leader: smallest sequence. If leader dies, ephemeral node deleted → next-smallest becomes leader."),
        quiz("zk-6","What is ZooKeeper's ZAB protocol?","hard",("zookeeper",),("ZooKeeper Atomic Broadcast: consensus protocol ensuring all nodes agree on the order of state changes","A gossip communication protocol used to check member health","A cache coherence protocol that invalidates stale memory keys","A load balancing rule that routes client traffic to free nodes"),0,"ZAB: leader broadcasts proposals → followers acknowledge → quorum commit. Similar to Raft/Paxos."),
        quiz("zk-7","What is a watch in ZooKeeper?","hard",("zookeeper",),("A one-time notification trigger: client registers a watch on a znode and gets notified on change","A monitoring daemon that checks server disk space consumption","A client-side polling function that queries the server repeatedly","A persistent subscription channel that streams all node updates"),0,"Watches are one-shot: triggered once, must re-register. Used for configuration changes, leader changes."),
        quiz("zk-8","How does distributed locking work with ZooKeeper?","hard",("zookeeper",),("Create ephemeral sequential node under /lock; lowest sequence holds the lock; watch the predecessor","Acquiring a filesystem lock on the physical server configuration","Running a SELECT FOR UPDATE query on a relational database table","Executing a Redis SETNX command with an expiration timeout"),0,"Fair locking: each client watches only the node before it (avoids thundering herd on unlock)."),
        quiz("zk-9","What is ZooKeeper's consistency model?","hard",("zookeeper",),("Sequential consistency with linearizable writes: writes are ordered, reads may be stale unless using sync()","Weak consistency where reads and writes can be lost under load","Eventual consistency where all replicas update asynchronously without order","Strictly linearizable consistency for all read and write queries"),0,"Reads can return stale data (from any server). Use sync() before read for linearizable guarantee."),
        quiz("zk-10","What is the ZooKeeper ensemble?","medium",("zookeeper",),("A group of ZK servers (typically 3 or 5) that form a quorum for fault tolerance","A single standalone server node running the coordination service","A client-side software library used to connect to coordinators","A system monitoring daemon that tracks cluster memory usage"),0,"3 servers tolerate 1 failure. 5 servers tolerate 2. Always use odd numbers for clear majority."),
        quiz("zk-11","What is ZooKeeper's session?","hard",("zookeeper",),("A persistent connection between client and server with a timeout — ephemeral nodes live within a session","An HTTP session cookie used to track dashboard users","A persistent TCP database connection pool identifier","A cache expiration timeout set on in-memory keys"),0,"Session has a timeout. If client disconnects > timeout, session expires and ephemeral nodes are deleted."),
        quiz("zk-12","What is the difference between ZooKeeper and etcd?","hard",("zookeeper",),("ZK: Java, ZAB protocol, used by Kafka/HBase. etcd: Go, Raft protocol, used by Kubernetes","They are identical systems developed by the same software group","ZooKeeper uses Raft consensus while etcd relies on ZAB","etcd is written in Java while ZooKeeper is written in Go"),0,"etcd: simpler API (HTTP/gRPC), better for Kubernetes. ZK: more mature, used by Hadoop ecosystem."),
        quiz("zk-13","How does Kafka use ZooKeeper?","hard",("zookeeper",),("Broker registration, topic/partition metadata, controller election, and consumer group coordination (legacy)","Storing raw client consumer records for fast access caching","Persisting published message payloads to disk storage","Routing individual messages to specific partition workers"),0,"Kafka is moving away from ZooKeeper (KRaft mode). Previously: controller election, metadata, ACLs."),
        quiz("zk-14","What is the herd effect in ZooKeeper?","hard",("zookeeper",),("All clients watching the same node get notified simultaneously on change, causing a thundering herd","A consensus failure where nodes disagree on partition leaders","A replication loop that causes duplicate entries across nodes","A memory optimization that shares data paths between sessions"),0,"Mitigation: watch only predecessor node (distributed locking) instead of the parent node."),
        quiz("zk-15","What is ZooKeeper's data model?","medium",("zookeeper",),("A hierarchical tree of znodes (like a filesystem) where each node can store data and have children","A standard key-value memory database with no node hierarchy","A document store containing indexed JSON files in folders","A network graph model connecting data vertices with edges"),0,"Path-based: /app/config/db-host. Max 1MB per znode. Not designed for large data storage."),
        quiz("zk-16","What is a multi-operation (multi) in ZooKeeper?","hard",("zookeeper",),("Execute multiple operations atomically: all succeed or all fail (create, set, delete in one transaction)","Opening multiple concurrent client connections to different nodes","A replication stage that copies folders across datacenter pools","A batch read query that retrieves data from multiple znodes"),0,"multi(): atomic batch operations. Create lock node + set config + delete old node atomically."),
        quiz("zk-17","What is ZooKeeper's read scalability?","hard",("zookeeper",),("Reads can be served by any server (not just leader) — adding more followers increases read throughput","ZooKeeper does not allow read queries when the leader is writing","Reads can only be processed by the leader node to prevent stale data","Read scalability is restricted to a fixed count of client sessions"),0,"Reads from followers may be stale. Writes go through leader only. Read-heavy workloads scale well."),
        quiz("zk-18","What are ACLs in ZooKeeper?","medium",("zookeeper",),("Access Control Lists: control which clients can read/write/create/delete znodes","Replication configuration settings that determine file counts","Network port routing rules defined at the firewall layer","Consensus voting credentials exchanged during leader election"),0,"ACL schemes: world, auth, digest, ip. Each znode has its own ACL. Important for multi-tenant setups."),
        quiz("zk-19","What is the curator framework?","hard",("zookeeper",),("A high-level Java client library for ZooKeeper providing recipes: leader election, locks, barriers, caches","A system monitoring utility that tracks ZooKeeper node memory","A database backup tool that saves znode states to flat files","A graphical user interface dashboard for managing znodes"),0,"Curator simplifies ZK usage with reusable recipes. Handles connection management and retry logic."),
        quiz("zk-20","When should you NOT use ZooKeeper?","hard",("zookeeper",),("For storing large data (>1MB/node), high-throughput reads/writes, or as a message queue or database","You should always choose ZooKeeper for all application configurations","When coordinates must be shared across more than three microservices","ZooKeeper should never be bypassed for relational storage requirements"),0,"ZK is for small metadata and coordination. Not a general-purpose store. New projects may prefer etcd or Consul."),
    ))
